import React, { useEffect, useState } from 'react';
import { fetchMeals, addMeal, deleteMeal, updateMeal } from '../services/api';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';

const Dashboard = () => {
    const [meals, setMeals] = useState([]);
    const [selectedDate, setSelectedDate] = useState(new Date().toISOString().split('T')[0]);
    const [form, setForm] = useState({ name: '', calories: '', type: 'breakfast' });
    const [editingId, setEditingId] = useState(null);

    // Get username from localStorage (set during login) or default to "User"
    const username = localStorage.getItem('username') || 'User';

    useEffect(() => { 
        loadMeals(); 
    }, []);

    const loadMeals = async () => {
        try {
            const { data } = await fetchMeals();
            setMeals(data || []);
        } catch (err) { 
            console.error("Failed to load meals"); 
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!form.name || !form.calories) return alert("Please fill all fields");

        try {
            if (editingId) {
                await updateMeal(editingId, { ...form, date: selectedDate });
                setEditingId(null);
            } else {
                await addMeal({ ...form, date: selectedDate });
            }
            setForm({ name: '', calories: '', type: 'breakfast' });
            loadMeals();
        } catch (err) {
            alert("Error saving meal");
        }
    };

    const handleEdit = (meal) => {
        setEditingId(meal._id);
        setForm({ name: meal.name, calories: meal.calories, type: meal.type });
        setSelectedDate(meal.date.split('T')[0]);
    };

    const getChartData = () => {
        const last7Days = [...Array(7)].map((_, i) => {
            const d = new Date();
            d.setDate(d.getDate() - i);
            return d.toISOString().split('T')[0];
        }).reverse();

        return last7Days.map(date => {
            const dayTotal = meals
                .filter(m => m.date && m.date.startsWith(date))
                .reduce((sum, m) => sum + Number(m.calories), 0);
            return { 
                day: date.split('-').slice(1).join('/'), // Formats to MM/DD
                calories: dayTotal 
            };
        });
    };

    const dailyMeals = meals.filter(m => m.date && m.date.startsWith(selectedDate));
    const totalCalories = dailyMeals.reduce((sum, m) => sum + Number(m.calories), 0);

    const handleLogout = () => {
        localStorage.clear();
        window.location.href = '/login';
    };

    return (
        <div className="p-4 md:p-8 max-w-6xl mx-auto min-h-screen bg-gray-50">
            {/* Header */}
            <header className="flex justify-between items-center mb-8 bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                <div>
                    <h1 className="text-2xl font-extrabold text-gray-900 tracking-tight">Diet Tracker</h1>
                    <p className="text-sm text-gray-500 font-medium">Hello, <span className="text-blue-600">{username}</span></p>
                </div>
                <button 
                    onClick={handleLogout} 
                    className="bg-red-50 text-red-600 px-5 py-2 rounded-xl font-bold hover:bg-red-100 transition duration-200"
                >
                    Logout
                </button>
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

                {/* LEFT COLUMN: Controls & Stats (Span 4) */}
                <div className="lg:col-span-4 space-y-6">
                    {/* Calories Summary Card */}
                    <div className="bg-blue-600 p-8 rounded-3xl text-white shadow-xl shadow-blue-200 relative overflow-hidden">
                        <div className="relative z-10">
                            <h3 className="text-blue-100 text-xs uppercase tracking-widest font-bold">Today's Intake</h3>
                            <p className="text-6xl font-black mt-2">{totalCalories}</p>
                            <p className="text-blue-200 text-sm font-medium mt-1">Total kcal consumed</p>
                        </div>
                        <div className="absolute -right-4 -bottom-4 w-24 h-24 bg-blue-500 rounded-full opacity-50"></div>
                    </div>

                    {/* Date Selector */}
                    <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                        <label className="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">View History</label>
                        <input 
                            type="date" 
                            value={selectedDate} 
                            onChange={(e) => setSelectedDate(e.target.value)} 
                            className="w-full p-3 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none font-medium text-gray-700" 
                        />
                    </div>

                    {/* Add/Edit Form */}
                    <form onSubmit={handleSubmit} className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100">
                        <h3 className="font-bold mb-5 text-gray-800 flex items-center">
                            <span className={`w-2 h-2 rounded-full mr-2 ${editingId ? 'bg-orange-500' : 'bg-green-500'}`}></span>
                            {editingId ? 'Edit This Meal' : 'Add a New Meal'}
                        </h3>
                        <input required placeholder="What did you eat?" value={form.name} onChange={e => setForm({...form, name: e.target.value})} className="w-full mb-3 p-3 border border-gray-200 rounded-xl focus:border-blue-500 outline-none" />
                        <input required type="number" placeholder="Calories (e.g. 350)" value={form.calories} onChange={e => setForm({...form, calories: e.target.value})} className="w-full mb-3 p-3 border border-gray-200 rounded-xl focus:border-blue-500 outline-none" />
                        <select value={form.type} onChange={e => setForm({...form, type: e.target.value})} className="w-full mb-5 p-3 border border-gray-200 rounded-xl focus:border-blue-500 outline-none bg-white">
                            <option value="breakfast">Breakfast</option>
                            <option value="lunch">Lunch</option>
                            <option value="dinner">Dinner</option>
                            <option value="snack">Snack</option>
                        </select>
                        <button className={`w-full py-4 rounded-xl font-bold text-white shadow-lg transition duration-200 ${editingId ? 'bg-orange-500 hover:bg-orange-600 shadow-orange-100' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-100'}`}>
                            {editingId ? 'Update Entry' : 'Add to Log'}
                        </button>
                        {editingId && (
                            <button type="button" onClick={() => {setEditingId(null); setForm({name:'', calories:'', type:'breakfast'})}} className="w-full mt-3 text-gray-400 text-sm font-bold hover:text-gray-600">
                                Cancel Edit
                            </button>
                        )}
                    </form>
                </div>

                {/* RIGHT COLUMN: Chart & Table (Span 8) */}
                <div className="lg:col-span-8 space-y-8">

                    {/* Weekly Chart */}
                    <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100">
                        <h3 className="font-bold mb-6 text-gray-800 text-lg">Weekly Calorie Trends</h3>
                        <div className="h-64">
                            <ResponsiveContainer width="100%" height="100%">
                                <BarChart data={getChartData()}>
                                    <XAxis dataKey="day" axisLine={false} tickLine={false} tick={{fill: '#9CA3AF', fontSize: 12}} dy={10} />
                                    <YAxis hide />
                                    <Tooltip cursor={{fill: '#F9FAFB'}} contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}} />
                                    <Bar dataKey="calories" radius={[6, 6, 0, 0]} barSize={40}>
                                        {getChartData().map((entry, index) => (
                                            <Cell key={`cell-${index}`} fill={entry.calories > 2500 ? '#EF4444' : '#3B82F6'} />
                                        ))}
                                    </Bar>
                                </BarChart>
                            </ResponsiveContainer>
                        </div>
                    </div>

                    {/* Meal Table */}
                    <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden">
                        <div className="p-6 border-b border-gray-50 flex justify-between items-center">
                            <h3 className="font-bold text-gray-800">Meal Log — {selectedDate}</h3>
                            <span className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1 rounded-full uppercase">{dailyMeals.length} Items</span>
                        </div>
                        <div className="overflow-x-auto">
                            <table className="w-full text-left">
                                <thead className="bg-gray-50/50">
                                    <tr>
                                        <th className="p-5 text-xs font-bold text-gray-400 uppercase tracking-widest">Meal Name</th>
                                        <th className="p-5 text-xs font-bold text-gray-400 uppercase tracking-widest">Category</th>
                                        <th className="p-5 text-xs font-bold text-gray-400 uppercase tracking-widest">Calories</th>
                                        <th className="p-5 text-right text-xs font-bold text-gray-400 uppercase tracking-widest">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-50">
                                    {dailyMeals.length > 0 ? dailyMeals.map(meal => (
                                        <tr key={meal._id} className="hover:bg-blue-50/30 transition group">
                                            <td className="p-5 font-bold text-gray-700">{meal.name}</td>
                                            <td className="p-5">
                                                <span className="px-3 py-1 bg-gray-100 text-gray-500 rounded-lg text-xs font-bold capitalize">
                                                    {meal.type}
                                                </span>
                                            </td>
                                            <td className="p-5">
                                                <span className="text-lg font-black text-gray-800">{meal.calories}</span>
                                                <span className="text-gray-400 text-xs ml-1 font-bold">kcal</span>
                                            </td>
                                            <td className="p-5 text-right">
                                                <div className="flex justify-end gap-4 opacity-0 group-hover:opacity-100 transition">
                                                    <button onClick={() => handleEdit(meal)} className="text-orange-500 hover:text-orange-600 font-bold text-sm">Edit</button>
                                                    <button onClick={async () => { if(window.confirm('Remove this entry?')) { await deleteMeal(meal._id); loadMeals(); }}} className="text-red-500 hover:text-red-600 font-bold text-sm">Delete</button>
                                                </div>
                                            </td>
                                        </tr>
                                    )) : (
                                        <tr>
                                            <td colSpan="4" className="p-20 text-center">
                                                <p className="text-gray-400 font-medium">No meals recorded for this day.</p>
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </div>
                </div>

            </div>
        </div>
    );
};

export default Dashboard;
